import{bQ as t,aL as o,u as e,G as r}from"./chunks/framework.jc7iVf2j.js";const s=JSON.parse('{"title":"完整 Frontmatter 示例文章","description":"这是一段描述。它将作为文章的简短摘要显示在文章列表卡片中，并用于 SEO。","frontmatter":{"title":"完整 Frontmatter 示例文章","description":"这是一段描述。它将作为文章的简短摘要显示在文章列表卡片中，并用于 SEO。","date":"2026-05-10T00:00:00.000Z","tags":["教程","示例"],"categories":["技术分享"],"cover":"https://w.wallhaven.cc/full/ly/wallhaven-lywpjl.jpg","top":true,"copyright":true,"articleGPT":"这是一个自定义的“AI摘要”文字。通过在这里填写内容，文章顶部会出现一个看起来像 AI 生成的文章总结区块。","references":[{"title":"VitePress 官方文档","url":"https://vitepress.dev/"},{"title":"Markdown 语法","url":"https://markdown.com.cn/"}],"head":[["link",{"rel":"canonical","href":"https://knotens.org/posts/示例-元数据解析"}]]},"headers":[],"relativePath":"posts/示例-元数据解析.md","filePath":"posts/示例-元数据解析.md","lastUpdated":1778418763000}');const n=t({name:"posts/示例-元数据解析.md"},[["render",function(t,s,n,a,l,c){return o(),e("div",null,[...s[0]||(s[0]=[r('<p>在每一篇 Markdown 文章的最开头，用 <code>---</code> 包围的部分被称为 <strong>Frontmatter</strong>（元数据）。在我们的 <code>vitepress-theme-curve</code> 主题中，这些元数据决定了文章在网页中的各种呈现方式。</p><p>下面是我们在文件头部配置的各项元数据，以及它们对应在网页中的具体作用：</p><h2 id="_1-基础信息" tabindex="-1">1. 基础信息 <a class="header-anchor" href="#_1-基础信息" aria-label="Permalink to &quot;1. 基础信息&quot;">​</a></h2><ul><li><strong><code>title</code></strong>: 对应网页中的 <strong>文章主标题（H1）</strong>。它会显示在文章详情页的最顶部，同时也会作为标签页的标题（Title）和文章列表中卡片的标题。</li><li><strong><code>description</code></strong>: 对应网页中的 <strong>文章摘要</strong>。当你浏览“文章列表”或“首页分类卡片”时，标题下方那段灰色的简短描述就是它。如果不写，系统可能会尝试从正文提取。它对 SEO 非常重要。</li><li><strong><code>date</code></strong>: 对应文章的 <strong>发布日期</strong>。它会显示在文章标题下方的元信息栏中，同时系统会通过它将文章排序，以及将文章归档到“文库 -&gt; 归档”页面的对应年份里。</li></ul><h2 id="_2-分类与标签" tabindex="-1">2. 分类与标签 <a class="header-anchor" href="#_2-分类与标签" aria-label="Permalink to &quot;2. 分类与标签&quot;">​</a></h2><ul><li><strong><code>categories</code></strong>: 对应网页中的 <strong>文章分类</strong>。它会出现在文章标题下方（带文件夹图标），点击可以跳转到该分类页面。通常一篇文章建议只设置一个主要分类。</li><li><strong><code>tags</code></strong>: 对应网页中的 <strong>文章标签</strong>。它同样显示在标题下方（带井号 <code>#</code> 图标），同时文章底部的也会列出标签。你可以设置多个标签。</li></ul><h2 id="_3-视觉与展示控制" tabindex="-1">3. 视觉与展示控制 <a class="header-anchor" href="#_3-视觉与展示控制" aria-label="Permalink to &quot;3. 视觉与展示控制&quot;">​</a></h2><ul><li><strong><code>cover</code></strong>: 对应文章的 <strong>封面图</strong>。它不仅会作为背景横幅出现在文章详情页的顶部，还会作为配图显示在首页或文章列表的文章卡片中。</li><li><strong><code>top</code></strong>: 对应文章的 <strong>置顶功能</strong>。设置为 <code>true</code> 会让这篇文章无视发布日期，固定排在文章列表的最前面。</li></ul><h2 id="_4-特殊组件控制" tabindex="-1">4. 特殊组件控制 <a class="header-anchor" href="#_4-特殊组件控制" aria-label="Permalink to &quot;4. 特殊组件控制&quot;">​</a></h2><ul><li><strong><code>articleGPT</code></strong>: 对应网页中的 <strong>AI 摘要区块</strong>。如果你填写了这一段文字，文章正文的开头上方会自动生成一个炫酷的“AI 阅读总结”卡片。</li><li><strong><code>references</code></strong>: 对应网页底部的 <strong>参考资料列表</strong>。它会在文章末尾自动生成一个引用链接区块，包含你配置的参考文章名称和链接。</li><li><strong><code>copyright</code></strong>: 对应网页底部的 <strong>版权声明卡片</strong>。默认开启（<code>true</code>），会在文章底部显示“本文作者、文章链接、版权协议（如 CC BY-NC-SA 4.0）”。如果某篇文章不需要显示（比如短笔记），可以设置为 <code>false</code> 来隐藏它。</li></ul>',10)])])}]]);export{s as __pageData,n as default};
